import{_ as s,o as n,c as e,a4 as t}from"./chunks/framework.BDOgl-CJ.js";const u=JSON.parse('{"title":"均值、方差、标准差","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/mean-variance-std.md","filePath":"ai-learning-notes/mean-variance-std.md","lastUpdated":1779177473000}'),i={name:"ai-learning-notes/mean-variance-std.md"};function p(l,a,o,c,d,r){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="均值、方差、标准差" tabindex="-1">均值、方差、标准差 <a class="header-anchor" href="#均值、方差、标准差" aria-label="Permalink to &quot;均值、方差、标准差&quot;">​</a></h1><h2 id="均值-mean" tabindex="-1">均值（Mean） <a class="header-anchor" href="#均值-mean" aria-label="Permalink to &quot;均值（Mean）&quot;">​</a></h2><p>平均水平。所有值加起来除以个数。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据：90, 60, 75, 88</span></span>
<span class="line"><span>均值 = (90 + 60 + 75 + 88) / 4 = 78.25</span></span></code></pre></div><h2 id="方差-variance" tabindex="-1">方差（Variance） <a class="header-anchor" href="#方差-variance" aria-label="Permalink to &quot;方差（Variance）&quot;">​</a></h2><p>数据有多「散」——和均值差的平方的平均。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(90 - 78.25)² = 11.75² = 138</span></span>
<span class="line"><span>(60 - 78.25)² = (-18.25)² = 333</span></span>
<span class="line"><span>(75 - 78.25)² = (-3.25)² = 11</span></span>
<span class="line"><span>(88 - 78.25)² = 9.75² = 95</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方差 = (138 + 333 + 11 + 95) / 4 = 144</span></span></code></pre></div><p>平方是为了消掉正负号——偏离 +11.75 和 -18.25 都是「偏离」，平方后都变正。</p><blockquote><p>方差的单位是「分²」，不直观。</p></blockquote><h2 id="标准差-standard-deviation" tabindex="-1">标准差（Standard Deviation） <a class="header-anchor" href="#标准差-standard-deviation" aria-label="Permalink to &quot;标准差（Standard Deviation）&quot;">​</a></h2><p>方差的平方根，单位回到原来的「分」。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>标准差 = √144 = 12</span></span></code></pre></div><p>意思：「这个班的成绩平均偏离均值 12 分左右」。</p><h2 id="计算步骤" tabindex="-1">计算步骤 <a class="header-anchor" href="#计算步骤" aria-label="Permalink to &quot;计算步骤&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始数据 ──→ 求平方差 ──→ 求平均 ──→ 开方 ──→ 标准差</span></span>
<span class="line"><span>90,60...     138,333...    144        12</span></span></code></pre></div><h2 id="在归一化中的作用" tabindex="-1">在归一化中的作用 <a class="header-anchor" href="#在归一化中的作用" aria-label="Permalink to &quot;在归一化中的作用&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>归一化后 = (原始值 - 均值) / 标准差</span></span>
<span class="line"><span></span></span>
<span class="line"><span>张三语文 = (90 - 78.25) / 12 = 0.98  ← 高于平均</span></span>
<span class="line"><span>李四语文 = (60 - 78.25) / 12 = -1.52 ← 低于平均</span></span></code></pre></div><p>归一化后：正数 = 高于平均，负数 = 低于平均，绝对值大小 = 偏离多少个标准差。</p>`,18)])])}const b=s(i,[["render",p]]);export{u as __pageData,b as default};
